                case AF_INET:
                        ip = ALLOC(sockaddr_in);
                        bzero((voidp) ip, sizeof(*ip));
                        ip->sin_family = AF_INET;
!                       bcopy((voidp) hp->h_addr, (voidp) &ip->sin_addr, sizeof(
ip->sin_addr)); 

                        ip->sin_port = htons(NFS_PORT);
                        break;
